    80→  process.exit(1);
    81→}
    82→
    83→/**
    84→ * Clean up old temporary execution files from previous runs
    85→ */
    86→function cleanupOldTempFiles() {
    87→  try {
    88→    const files = fs.readdirSync(__dirname);
